tinymce.PluginManager.add('exportpdf', function(editor, url) {
	let pdfScriptsReady; // Promise that resolves when all scripts are injected
	const FONT_REGISTRY = {
		"UKIJEkranRegular": "/editor/assets/fonts/UKIJEkran.ttf",
		"UKIJChiwerKesmeRegular": "/editor/assets/fonts/UKIJKesme.ttf",
		"UKIJCJKRegular": "/editor/assets/fonts/UKIJCJK.ttf",
		"UKIJKufiRegular": "/editor/assets/fonts/UKIJKu.ttf"
	}; 
	
    // Add button to toolbar
    editor.ui.registry.addButton('exportpdf', {
        text: 'Export as PDF',
        icon: 'image',
        tooltip: 'Export as PDF',
        onAction: async function() {
            generatePDF();
        }
    });

    // Add menu item
    editor.ui.registry.addMenuItem('exportpdf', {
        text: 'Export as PDF',
        icon: 'image',
        onAction: async function() {
            generatePDF();
        }
    });
	
	function getFontsUsed(root) {
		const fonts = new Set();

		root.querySelectorAll("*").forEach(el => {
		    const style = window.getComputedStyle(el);
		    const family = style.fontFamily.split(",")[0].replace(/['"]/g, "").trim();
		    if (family) fonts.add(family);
		});

		return [...fonts];
	}
	
	async function fontToBase64(url) {
		const res = await fetch(url);
		const buffer = await res.arrayBuffer();

		let binary = "";
		const bytes = new Uint8Array(buffer);
		const len = bytes.byteLength;

		for (let i = 0; i < len; i++) {
		    binary += String.fromCharCode(bytes[i]);
		}

		return btoa(binary);
	}
	
	async function getSystemFontBase64(family) {
		if (!window.queryLocalFonts) return null;
		const font = (await window.queryLocalFonts()).find(f => f.fullName === family);
		if (!font) return null;
		const blob = await font.blob();
		return await new Promise(r => {
		    const fr = new FileReader();
		    fr.onloadend = () => r(fr.result.split(",")[1]);
		    fr.readAsDataURL(blob);
		});
	}
		
	async function registerFonts(pdf, fonts) {
		for (const family of fonts) {
		    const url = FONT_REGISTRY[family];
		    if (url) {
		    	// get hosted fonts
				const base64 = await fontToBase64(url);

				pdf.addFileToVFS(family + ".ttf", base64);
				pdf.addFont(family + ".ttf", family, "normal");
		    } else {
		    	// get system fonts
		        const base64 = await getSystemFontBase64(family);
		        if (base64) {
		            pdf.addFileToVFS(family + ".ttf", base64);
		            pdf.addFont(family + ".ttf", family, "normal");
		        } else {
		            console.warn(`Font ${family} not found on system`);
		        }		    	
		    }
		}
		
	}

	function applyBidiEngine(root, bidi) {
		// Select all elements explicitly marked as RTL
		root.querySelectorAll("[dir='rtl']").forEach(el => {

		    // Walk all text nodes inside this element
		    const walker = document.createTreeWalker(el, NodeFilter.SHOW_TEXT, null, false);
		    let node;
		    while ((node = walker.nextNode())) {
		        const text = node.nodeValue.trim();

		        if (text) {
		            // Set BiDi engine options for RTL processing
		            bidi.setOptions({
		                isInputVisual: false,
		                isOutputVisual: true,
		                isInputRtl: true,
		                isOutputRtl: true,
		                isSymmetricSwapping: true
		            });

		            // Apply BiDi reordering (mirrors brackets, reorders text)
		            node.nodeValue = bidi.doBidiReorder(text);
		        }
		    }
		});
	}
	function downloadFile(doc) {
		// Convert the document to full HTML
		var source = "<!DOCTYPE html>\n" + doc.documentElement.outerHTML;

		// Create file
		var blob = new Blob([source], { type: "text/html;charset=utf-8" });

		var a = document.createElement("a");
		a.href = URL.createObjectURL(blob);
		a.download = "index.html";
		a.click();

		URL.revokeObjectURL(a.href);
	}	

	async function embedFontsInDoc(doc, fonts) {

		const style = doc.createElement("style");
		style.type = "text/css";

		let css = "";

		for (const family of fonts) {

			const url = FONT_REGISTRY[family];
			if (!url) continue;

			const base64 = await fontToBase64(url);

			css += `
			@font-face {
				font-family: '${family}';
				src: url(data:font/ttf;base64,${base64}) format('truetype');
				font-weight: normal;
				font-style: normal;
			}
			`;
		}

		style.appendChild(doc.createTextNode(css));
		doc.head.appendChild(style);
	}	

	function registerFontsFromEditorDoc(pdf, doc) {
		// Read <style> tags from the editor iframe document
		const styles = doc.querySelectorAll("style");

		styles.forEach(style => {
		    const css = style.textContent;
		    const regex = /@font-face\s*{[^}]*font-family:\s*['"]?([^;'"]+)['"]?;[^}]*src:\s*url\(data:font\/[^;]+;base64,([^)]*)\)/g;
		    let match;
		    while ((match = regex.exec(css)) !== null) {
		        const family = match[1].trim();
		        const base64 = match[2].trim();
		        const filename = family + ".ttf";
		        console.log("Registering font from editor doc:", family);
		        pdf.addFileToVFS(filename, base64);
		        pdf.addFont(filename, family, "normal");
		    }
		});
	}	

	
	
	async function generatePDF() {
		const { jsPDF } = window.jspdf;
		var pdf = new jsPDF('p', 'pt', 'a4');

		var doc = editor.getDoc();
		const fonts = getFontsUsed(doc.body);
		//console.log("Used fonts:", fonts);

		// Step 1: Embed fonts into the EDITOR iframe doc (for layout rendering)
		await embedFontsInDoc(doc, fonts);
		
        //downloadFile(doc);
		// Trigger the function that's already living inside the iframe
		var iframeWindow = editor.getWin();
		await iframeWindow.generatePDF();
	}

	editor.on('init', function() {
		var doc = editor.getDoc();

		pdfScriptsReady = new Promise((resolve) => {
		    var s1 = doc.createElement('script');
		    s1.src = 'https://html2canvas.hertzen.com/dist/html2canvas.js';
		    doc.head.appendChild(s1);

		    s1.onload = function() {
		        var s2 = doc.createElement('script');
		        s2.src = '/editor/assets/jspdf.umd.min.js';
		        doc.head.appendChild(s2);

		        s2.onload = function() {
		            var s3 = doc.createElement('script');
		            s3.textContent = `
		                function registerFontsFromStyles(pdf) {
		                    const styles = document.querySelectorAll("style");
		                    styles.forEach(style => {
		                        const css = style.textContent;
		                        const regex = /@font-face\\s*{[^}]*font-family:\\s*['"]?([^;'"]+)['"]?;[^}]*src:\\s*url\\(data:font\\/[^;]+;base64,([^)]*)\\)/g;
		                        let match;
		                        while ((match = regex.exec(css)) !== null) {
		                            const family = match[1];
		                            const base64 = match[2];
		                            const filename = family + ".ttf";
		                            pdf.addFileToVFS(filename, base64);
		                            pdf.addFont(filename, family, "normal");
		                        }
		                    });
		                }

		                window.generatePDF = async function() {
		                    const { jsPDF } = window.jspdf;
		                    var pdf = new jsPDF('p', 'pt', 'a4');
		                    registerFontsFromStyles(pdf);
		                    pdf.html(document.body, {
		                        callback: function(pdf) {
		                            pdf.output("dataurlnewwindow");
		                        },
		                        x: 0,
		                        y: 0,
		                        width: 555.28,
		                        windowWidth: 712.100,
		                    });
		                };
		            `;
		            doc.body.appendChild(s3);
		            resolve(); // all scripts injected and ready
		        };
		    };
		});
	});

    return {
        getMetadata: function() {
            return {
                name: 'Export as PDF',
                url: 'http://yoursite.com'
            };
        }
    };
});
